var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"어디로 갔나 했더니 여기 있었구나, 류드밀라?","JPN":"どこにいったのかと思っていたら、ここにいたのね、リュドミラ？","ENG":"I was wondering where you went to, Lyudmila.","TWN":"盧德米拉，我還想說你跑哪去了，原來在這裡。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다른 애들이 함교에서 기다리는 중이야.","JPN":"子どもたちが艦橋で待っているわ。","ENG":"The others are waiting for you on the bridge.","TWN":"其他人都在艦橋上等著。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"연회 같은 건 싫어해도 건배사 할 때까진 동석하면 안 될까?","JPN":"宴会が嫌いなのはわかるけど、乾杯の挨拶まではいてくれないかしら？","ENG":"I know you hate parties, but can't you at least stay until the toast?","TWN":"我知道你不喜歡這種社交場合，但起碼待到致詞完吧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"미안하군, 알렉스. 대원들의 노고를 치하하는 자리에 빠질 생각은 없었다.","JPN":"すまない、アレックス。隊員たちの苦労を労う席から抜け出すつもりはなかったんだが。","ENG":"Apologies, Alex. I did not intend to avoid an event where my comrades' hard work was being commended.","TWN":"抱歉，雅蕾克絲，我沒有要缺席慶功宴的意思。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"으음…… 일이 좀처럼 진척을 보이지 않으니 답답하군.","JPN":"ううむ……なかなかはかどらないからもどかしいな。","ENG":"Mm... It's frustrating because I cannot see any progress.","TWN":"只是……事情遲遲沒有進展，心情有點煩悶。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 테이블 위의 그건 뭐야?","JPN":"うん？　テーブルにあるそれは何なの？","ENG":"Hmm? What's that on the table?","TWN":"嗯？桌上那是什麼東西？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저건…… 제 생각이 맞다면 프라모델 같군요.","JPN":"あれは……おそらくプラモデルでしょう。","ENG":"I think... that's a plamodel.","TWN":"那是……我沒猜錯的話，應該是模型吧！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇다. 역시 눈썰미가 좋군, 예고르.","JPN":"その通り。すぐにわかるとはさすがだな、イェゴール。","ENG":"Correct. You have a keen eye, Yegor.","TWN":"沒錯，伊高爾的眼睛真利。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……정확히는 <color=#ffd34c>프라모델이었던 것</color>이라고 해야겠지만.","JPN":"……正確には<color=#ffd34c>プラモデルだったもの</color>というべきだが。","ENG":"...To be exact, it <color=#ffd34c>was a plamodel</color>.","TWN":"……但正確來說，應該是<color=#ffd34c>正常版的模型</color>。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"며칠 전에 이수연이 자기 집에서 귀한 브랜디를 개봉하자고 연락했다.","JPN":"数日前、カナミの方から自分の家で一緒に貴重なブランデーを開けないかと連絡があってな。","ENG":"A few days ago, Lee Sooyeon invited me to her home to open a precious bottle of brandy with her.","TWN":"前幾天李秀妍打給我，說她有一瓶高級的白蘭地，要找我去她家喝一杯。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"회사에 조금 일찍 도착하는 바람에, 일이 끝날 때까지 기다리고 있었다만…….","JPN":"会社に少し早く着いてしまって、仕事が終わるまで待っていたのだが……","ENG":"I had to wait for her to get off work as I arrived at the company earlier than expected...","TWN":"我那天有點早到公司，所以就在公司等她忙完……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"응? 이건……?","JPN":"ん？　これは……？","ENG":"Hmm? Isn't that...?","TWN":"嗯？這是……？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"재질로 보아…… 대원들이 말했던 프라모델이란 건가?","JPN":"材質から見て……これが隊員たちが話していたプラモデルというものか？","ENG":"Judging from the materials used... is this the plamodel they were talking about?","TWN":"看它的材質……這就是隊員們說的模型嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 휴게실에서 조립된 프라모델을 발견했다.","JPN":"コフィンカンパニー休憩室で完成しているプラモデルを見つけた。","ENG":"I found an assembled plamodel in Coffin Company's break room.","TWN":"我在科芬公司的休息室裡發現組裝好的模型。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들의 이야기대로 실물만큼 정교하게 생겼군. 만들어 보고 싶은 욕구가 생길 정도다.","JPN":"隊員たちが話していたとおり、まるで実物のような精巧さだ。作ってみたいという欲求が湧いてくる。","ENG":"It looks as detailed as the real thing, just as they have told me. It makes me want to assemble one myself.","TWN":"確實就像隊員們所說的一樣，實品非常精緻，精緻到我也想動手做做看。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 프라모델의 형태가…… 누군가와 무척 닮은 것 같다.","JPN":"しかしこのプラモデルの形は……誰かによく似ている気がする。","ENG":"However, the shape of this model... looks very familiar to someone I know.","TWN":"不過那個模型的外觀……長得和某人非常像。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"정확한 판단을 위해 잠시 만져 보도록 하겠다.","JPN":"正確な判断を下すために、少しばかり触ってみるとしよう。","ENG":"To get a better assessment, I'll briefly touch it.","TWN":"因此我決定先摸摸看再做決定。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"오오, 관절부의 가동 범위가 경이롭군.","JPN":"おお、関節の可動域が驚異的なレベルだ。","ENG":"Ooh, the movement range of its joints is remarkable.","TWN":"哇喔，可以動的關節部分非常驚人。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};